class Solution {
    public int findTheLongestSubstring(String s) {
        int maxLen = 0;
        int[] vowelCount = new int[5]; // a, e, i, o, u
        int mask = 0;
        Map<Integer, Integer> seen = new HashMap<>();
        seen.put(0, -1);

        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            if (c == 'a') {
                vowelCount[0] ^= 1;
            } else if (c == 'e') {
                vowelCount[1] ^= 1;
            } else if (c == 'i') {
                vowelCount[2] ^= 1;
            } else if (c == 'o') {
                vowelCount[3] ^= 1;
            } else if (c == 'u') {
                vowelCount[4] ^= 1;
            }

            mask = 0;
            for (int j = 0; j < 5; j++) {
                if (vowelCount[j] % 2 != 0) {
                    mask |= (1 << j);
                }
            }

            if (seen.containsKey(mask)) {
                maxLen = Math.max(maxLen, i - seen.get(mask));
            } else {
                seen.put(mask, i);
            }
        }

        return maxLen;
    }
}
